SELECT year_id, MAX(happiness_score) AS highest_happiness_score
FROM happiness_scores
GROUP BY year_id;

SELECT AVG(happiness_score) AS average_happiness_score
FROM happiness_scores
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'United States');

SELECT billionaires AS total_billionaires
FROM wealth_indicators
WHERE country_id = 1 AND year_id = 1;

SELECT country_id, AVG(gdp_per_capita) AS average_gdp_per_capita
FROM economic_indicators
GROUP BY country_id;
